def user_embedding(liked_item_ids: list[int], item_vecs: np.ndarray) -> np.ndarray:
    liked_vecs = item_vecs[liked_item_ids]        # shape (L, D)
    mean_vec = liked_vecs.mean(axis=0, keepdims=True)
    # Re-normalise after averaging (average of unit vectors is not unit)
    norm = np.linalg.norm(mean_vec, axis=1, keepdims=True)
    return (mean_vec / norm).astype(np.float32)


def recommend_for_user(
    liked_item_ids: list[int],
    item_vecs: np.ndarray,
    index: faiss.Index,
    items: list[dict],
    k: int = 10,
) -> list[dict]:
    if not liked_item_ids:
        return []   # cold-start: fall back to popularity or onboarding quiz

    u_vec = user_embedding(liked_item_ids, item_vecs)
    scores, ids = index.search(u_vec, k + len(liked_item_ids))  # fetch extra to filter seen

    seen = set(liked_item_ids)
    results = []
    for r, i in enumerate(ids[0]):
        if i not in seen:
            results.append({"item": items[i], "score": float(scores[0][r])})
        if len(results) == k:
            break
    return results


